import json
from collections import defaultdict

lines = []
with open('/home/nakashima/projects/blade_management/.claude/logs/edit-history.jsonl', 'r') as f:
    for line in f:
        try:
            lines.append(json.loads(line.strip()))
        except:
            pass

# Now: key metric - true accuracy of affected_files
# Only 8 entries have affected_files (all from session 0faad0cd)
# The field isn't populated for most edits, making true impact analysis difficult

# But let's see what edit-A -> edit-B causality looks like from the data
# by looking at temporal sequence patterns

# For each session, group edits by "burst" (within 3 session_edit_count distance)
# and find which files are always edited together

print("=== Strong causal pairs (same session, edit count within 3, high frequency) ===")

# Build temporal adjacency
temporal_pairs = defaultdict(int)
for session_id in ['4e0e035f', '48cf9153', '81129fe1']:
    sess = sorted([e for e in lines if e['session_id'] == session_id],
                  key=lambda x: x['session_edit_count'])
    for i in range(len(sess)):
        for j in range(i+1, len(sess)):
            if sess[j]['session_edit_count'] - sess[i]['session_edit_count'] > 3:
                break
            f1 = sess[i]['file']
            f2 = sess[j]['file']
            if f1 != f2:
                pair = tuple(sorted([f1, f2]))
                temporal_pairs[pair] += 1

# Show top pairs
sorted_tp = sorted(temporal_pairs.items(), key=lambda x: -x[1])
for pair, count in sorted_tp[:15]:
    if count >= 4:
        # Only show non-docs pairs
        if 'plan.md' not in pair[0] and 'plan.md' not in pair[1] and 'review.md' not in pair[0]:
            print(f"  {count:3d}x  {pair[0]}  <->  {pair[1]}")

print("\n=== Including all (top 15, excluding pure docs) ===")
shown = 0
for pair, count in sorted_tp:
    if count < 3:
        break
    if not ('plan.md' in pair[0] or 'plan.md' in pair[1]):
        print(f"  {count:3d}x  {pair[0]}  <->  {pair[1]}")
        shown += 1
        if shown >= 15:
            break

